SELECT c.customer_id, c.age, r.risk_score
FROM customers c
LEFT JOIN risk_assessments r ON c.customer_id = r.customer_id;

SELECT cp.customer_id, cp.credit_score
FROM credit_profiles cp
WHERE cp.customer_id IN (
    SELECT c.customer_id
    FROM (
        SELECT customer_id FROM customers WHERE number_of_credit_cards > 0
        INTERSECT
        SELECT customer_id FROM loans WHERE car_loans IS NOT NULL
    ) c
) AND cp.credit_score < (SELECT AVG(credit_score) FROM credit_profiles);

SELECT AVG(cp.credit_score) AS Average_Credit_Score
FROM credit_profiles cp
JOIN loans l ON cp.customer_id = l.customer_id;

SELECT c.customer_id, c.education
FROM customers c
INNER JOIN credit_profiles cp ON c.customer_id = cp.customer_id;
